import React, { useState, useRef, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  Sparkles, 
  Bot, 
  Zap, 
  Code, 
  Database, 
  Cloud, 
  Rocket, 
  ArrowRight,
  Send,
  Loader,
  CheckCircle,
  AlertCircle,
  Download,
  Play,
  Settings,
  MessageSquare,
  Layout,
  Palette,
  Layers,
  Globe,
  Smartphone,
  ShoppingCart,
  BarChart3,
  MessageCircle,
  Users,
  FileText,
  Cog,
  ChevronDown,
  Star,
  Cpu,
  Clock,
  Wifi,
  Lightbulb,
  Wand2,
  GitBranch,
  Server,
  HardDrive,
  MousePointerClick
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import frameworkService from '../services/frameworkService';
import templateService from '../services/templateService';
import realtimeProjectService from '../services/realtimeProjectService';

// Enhanced animations
const pulse = keyframes`
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.7; transform: scale(1.05); }
`;

const slideUp = keyframes`
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
`;

const rotate = keyframes`
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
`;

const fadeInUp = keyframes`
  from { opacity: 0; transform: translateY(30px); }
  to { opacity: 1; transform: translateY(0); }
`;

const typing = keyframes`
  from { width: 0; }
  to { width: 100%; }
`;

const float = keyframes`
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
`;

const shimmer = keyframes`
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
`;

// Enhanced container with gradient background
const Container = styled.div`
  min-height: 100vh;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
  padding: 2rem;
`;

const Header = styled.div`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  padding: 3rem 2rem;
  text-align: center;
  border-radius: 1.5rem;
  margin-bottom: 2rem;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
  position: relative;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 70%);
    animation: ${rotate} 20s linear infinite;
  }
`;

const Title = styled.h1`
  font-size: 3rem;
  font-weight: 800;
  margin-bottom: 1rem;
  background: linear-gradient(45deg, #fff, #e2e8f0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  position: relative;
  z-index: 2;
`;

const Subtitle = styled.p`
  font-size: 1.25rem;
  opacity: 0.9;
  max-width: 700px;
  margin: 0 auto 1.5rem;
  position: relative;
  z-index: 2;
`;

const FeatureHighlights = styled.div`
  display: flex;
  justify-content: center;
  gap: 2rem;
  margin-top: 1.5rem;
  flex-wrap: wrap;
  position: relative;
  z-index: 2;
`;

const FeatureItem = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  background: rgba(255, 255, 255, 0.15);
  padding: 0.5rem 1rem;
  border-radius: 2rem;
  backdrop-filter: blur(10px);
`;

const MainContent = styled.div`
  display: grid;
  grid-template-columns: 1fr 400px;
  gap: 2rem;
  max-width: 1600px;
  margin: 0 auto;
  
  @media (max-width: 1200px) {
    grid-template-columns: 1fr;
  }
`;

const BuilderSection = styled.div`
  background: white;
  border-radius: 1.5rem;
  padding: 2rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  transition: all 0.3s ease;
  
  &:hover {
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.12);
    transform: translateY(-5px);
  }
`;

const SectionTitle = styled.h2`
  font-size: 1.75rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 1.5rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding-bottom: 1rem;
  border-bottom: 2px solid #f1f5f9;
`;

// Enhanced template grid
const TemplateGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const TemplateCard = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 1.5rem;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 2px solid ${props => props.selected ? '#667eea' : '#e2e8f0'};
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(102, 126, 234, 0.15);
    border-color: #667eea;
  }
  
  ${props => props.selected && `
    &::before {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      height: 4px;
      background: linear-gradient(90deg, #667eea, #764ba2);
    }
  `}
`;

const TemplateIcon = styled.div`
  width: 3.5rem;
  height: 3.5rem;
  border-radius: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  margin-bottom: 1rem;
`;

const TemplateName = styled.h3`
  font-size: 1.25rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.5rem 0;
`;

const TemplateDescription = styled.p`
  color: #64748b;
  font-size: 0.9rem;
  margin: 0 0 1rem 0;
  line-height: 1.5;
`;

// Enhanced framework section
const FrameworkSection = styled.div`
  background: #f8fafc;
  border-radius: 1rem;
  padding: 1.5rem;
  margin: 2rem 0;
  border: 1px solid #e2e8f0;
`;

const FrameworkGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 1rem;
  margin-top: 1rem;
`;

const FrameworkCard = styled.div`
  background: white;
  border-radius: 0.75rem;
  padding: 1.25rem;
  border: 2px solid ${props => props.selected ? '#667eea' : '#e2e8f0'};
  cursor: pointer;
  transition: all 0.2s ease;
  
  &:hover {
    border-color: #667eea;
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.1);
  }
  
  ${props => props.selected && `
    background: linear-gradient(135deg, #f0f4ff 0%, #e6f0ff 100%);
  `}
`;

const FrameworkHeader = styled.div`
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 0.75rem;
`;

const FrameworkIcon = styled.div`
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 0.5rem;
  background: #f1f5f9;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.25rem;
`;

const FrameworkName = styled.h4`
  font-size: 1.1rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
`;

const FrameworkDescription = styled.p`
  color: #64748b;
  font-size: 0.85rem;
  margin: 0;
  line-height: 1.4;
`;

const RecommendationBadge = styled.span`
  background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%);
  color: white;
  padding: 0.25rem 0.75rem;
  border-radius: 1rem;
  font-size: 0.75rem;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  margin-left: 0.5rem;
`;

const AdvancedToggle = styled.button`
  background: #f1f5f9;
  border: none;
  padding: 0.75rem 1.25rem;
  border-radius: 0.75rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  cursor: pointer;
  font-weight: 500;
  color: #1e293b;
  margin-bottom: 1.5rem;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e2e8f0;
  }
`;

const TechStackPreview = styled.div`
  background: white;
  border-radius: 0.75rem;
  padding: 1.25rem;
  border: 1px solid #e2e8f0;
  margin-top: 1.5rem;
`;

const TechStackItem = styled.div`
  display: flex;
  justify-content: space-between;
  padding: 0.75rem 0;
  border-bottom: 1px solid #f1f5f9;
  
  &:last-child {
    border-bottom: none;
  }
`;

const TechStackLabel = styled.span`
  font-weight: 500;
  color: #1e293b;
`;

const TechStackValue = styled.span`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: #64748b;
`;

const ActionButton = styled.button`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 1rem 2rem;
  border-radius: 0.75rem;
  font-size: 1.1rem;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  transition: all 0.3s ease;
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.3);
  width: 100%;
  
  &:hover:not(:disabled) {
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(102, 126, 234, 0.4);
  }
  
  &:disabled {
    opacity: 0.7;
    cursor: not-allowed;
    transform: none;
  }
`;

const LoadingSpinner = styled.div`
  display: inline-flex;
  animation: ${props => props.rotate && rotate} 1s linear infinite;
`;

const Sidebar = styled.div`
  background: white;
  border-radius: 1.5rem;
  padding: 1.5rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  height: fit-content;
`;

const ProgressCard = styled.div`
  background: linear-gradient(135deg, #f8fafc 0%, #ffffff 100%);
  border-radius: 1rem;
  padding: 1.5rem;
`;

const ProgressStep = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 1rem 0;
  border-bottom: 1px solid #f1f5f9;
  
  &:last-child {
    border-bottom: none;
  }
  
  &.completed {
    color: #10b981;
  }
  
  &.active {
    color: #667eea;
  }
  
  &.pending {
    color: #94a3b8;
  }
`;

const StepIcon = styled.div`
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  
  &.completed {
    background: #10b981;
    color: white;
  }
  
  &.active {
    background: #667eea;
    color: white;
  }
  
  &.pending {
    background: #e2e8f0;
    color: #94a3b8;
  }
`;

function Builder() {
  const navigate = useNavigate();
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [chatMessages, setChatMessages] = useState([
    {
      type: 'ai',
      content: '👋 Hi! I\'m your AI App Builder assistant. Tell me what application you want to build, or choose a template to get started!'
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentProject, setCurrentProject] = useState(null);
  const [buildSteps, setBuildSteps] = useState([
    { id: 1, name: 'Analyze Requirements', status: 'pending' },
    { id: 2, name: 'Generate Code', status: 'pending' },
    { id: 3, name: 'Setup Database', status: 'pending' },
    { id: 4, name: 'Configure APIs', status: 'pending' },
    { id: 5, name: 'Ready to Deploy', status: 'pending' }
  ]);
  
  // New framework-related state
  const [showFrameworkSelector, setShowFrameworkSelector] = useState(false);
  const [selectedFrameworks, setSelectedFrameworks] = useState({
    frontend: 'react',
    backend: 'fastapi',
    database: 'mysql'
  });
  const [supportedFrameworks, setSupportedFrameworks] = useState(null);
  const [frameworkRecommendations, setFrameworkRecommendations] = useState(null);
  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
  
  // Real-time creation state
  const [realtimeSession, setRealtimeSession] = useState(null);
  const [realtimeProgress, setRealtimeProgress] = useState(null);
  const [isRealtimeBuilding, setIsRealtimeBuilding] = useState(false);
  const [websocketConnected, setWebsocketConnected] = useState(false);

  // Load supported frameworks on component mount
  useEffect(() => {
    const loadFrameworks = async () => {
      try {
        const response = await frameworkService.getSupportedFrameworks();
        setSupportedFrameworks(response.frameworks);
      } catch (error) {
        console.error('Failed to load frameworks:', error);
      }
    };
    
    loadFrameworks();
    
    // Cleanup WebSocket connection on unmount
    return () => {
      if (realtimeProjectService.getIsConnected()) {
        realtimeProjectService.disconnect();
      }
    };
  }, []);

  const templates = [
    {
      id: 'dashboard',
      name: 'Analytics Dashboard',
      description: 'Business intelligence dashboard with charts, KPIs, and real-time data visualization',
      icon: BarChart3,
      features: ['Charts & Graphs', 'Real-time Data', 'User Management', 'Export Reports']
    },
    {
      id: 'ecommerce',
      name: 'E-commerce Store',
      description: 'Complete online store with product management, cart, and payment processing',
      icon: ShoppingCart,
      features: ['Product Catalog', 'Shopping Cart', 'Payment Gateway', 'Order Management']
    },
    {
      id: 'blog',
      name: 'Blog & CMS',
      description: 'Content management system with rich editor, comments, and SEO optimization',
      icon: FileText,
      features: ['Rich Text Editor', 'Comment System', 'SEO Tools', 'Media Management']
    },
    {
      id: 'chat',
      name: 'Chat Application',
      description: 'Real-time messaging platform with rooms, file sharing, and notifications',
      icon: MessageCircle,
      features: ['Real-time Chat', 'File Sharing', 'Chat Rooms', 'Push Notifications']
    },
    {
      id: 'crm',
      name: 'CRM System',
      description: 'Customer relationship management with contacts, deals, and sales pipeline',
      icon: Users,
      features: ['Contact Management', 'Sales Pipeline', 'Task Tracking', 'Reports']
    },
    {
      id: 'saas',
      name: 'SaaS Platform',
      description: 'Multi-tenant SaaS application with subscriptions and user management',
      icon: Cloud,
      features: ['Multi-tenancy', 'Subscription Billing', 'API Management', 'Analytics']
    }
  ];

  const examplePrompts = [
    "Build a task management app with team collaboration",
    "Create a social media platform with posts and likes",
    "Build an inventory management system for warehouses",
    "Create a booking system for appointments",
    "Build a learning management system for courses"
  ];

  const handleSendMessage = async () => {
    if (!inputMessage.trim() || isGenerating) return;

    const userMessage = inputMessage.trim();
    setInputMessage('');
    
    // Add user message
    setChatMessages(prev => [...prev, { type: 'user', content: userMessage }]);
    
    setIsGenerating(true);
    
    try {
      // Simulate AI processing
      setTimeout(() => {
        const aiResponse = generateAIResponse(userMessage);
        setChatMessages(prev => [...prev, { type: 'ai', content: aiResponse }]);
        
        // Start building process if user requested an app
        if (userMessage.toLowerCase().includes('build') || userMessage.toLowerCase().includes('create')) {
          startBuildProcess(userMessage);
        }
        
        setIsGenerating(false);
      }, 1500);
      
    } catch (error) {
      toast.error('Failed to process your request');
      setIsGenerating(false);
    }
  };

  const generateAIResponse = (message) => {
    const responses = [
      `Great idea! I'll help you build a ${extractAppType(message)}. Let me analyze your requirements and generate the complete application with React frontend, FastAPI backend, and MySQL database.`,
      `Perfect! I understand you want to create a ${extractAppType(message)}. I'll generate all the necessary components including authentication, database models, API endpoints, and a modern React interface.`,
      `Excellent choice! Building a ${extractAppType(message)} is a great project. I'll create a production-ready application with all the features you need, including proper security, responsive design, and deployment configurations.`
    ];
    
    return responses[Math.floor(Math.random() * responses.length)];
  };

  const extractAppType = (message) => {
    const types = {
      'dashboard': 'analytics dashboard',
      'ecommerce': 'e-commerce platform',
      'blog': 'blog platform',
      'chat': 'chat application',
      'crm': 'CRM system',
      'task': 'task management app',
      'social': 'social media platform',
      'inventory': 'inventory management system',
      'booking': 'booking system',
      'learning': 'learning management system'
    };
    
    for (const [key, value] of Object.entries(types)) {
      if (message.toLowerCase().includes(key)) {
        return value;
      }
    }
    
    return 'custom application';
  };

  const startBuildProcess = (description) => {
    setCurrentProject({ 
      name: extractAppType(description),
      description,
      startTime: new Date()
    });
    
    // Simulate build steps
    let currentStep = 0;
    const interval = setInterval(() => {
      setBuildSteps(prev => 
        prev.map((step, index) => {
          if (index === currentStep) {
            return { ...step, status: 'active' };
          } else if (index < currentStep) {
            return { ...step, status: 'completed' };
          }
          return step;
        })
      );
      
      currentStep++;
      if (currentStep >= buildSteps.length) {
        clearInterval(interval);
        setBuildSteps(prev => 
          prev.map(step => ({ ...step, status: 'completed' }))
        );
        toast.success('🎉 Application generated successfully!');
      }
    }, 2000);
  };

  const handleTemplateSelect = (template) => {
    setSelectedTemplate(template);
    const message = `Build a ${template.name.toLowerCase()} with the following features: ${template.features.join(', ')}`;
    setInputMessage(message);
  };

  const handleBuildFromTemplate = () => {
    if (!selectedTemplate) return;
    
    const message = `Build a ${selectedTemplate.name.toLowerCase()} - ${selectedTemplate.description}`;
    setChatMessages(prev => [...prev, { type: 'user', content: message }]);
    
    setIsGenerating(true);
    setTimeout(() => {
      setChatMessages(prev => [...prev, { 
        type: 'ai', 
        content: `Perfect! I'll build a ${selectedTemplate.name} for you. This will include ${selectedTemplate.features.join(', ')} and all the necessary backend infrastructure.`
      }]);
      startBuildProcess(message);
      setIsGenerating(false);
    }, 1000);
  };

  const handleDeployApp = () => {
    if (currentProject) {
      toast.success('Redirecting to deployment...');
      navigate('/deploy');
    }
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (realtimeProjectService.getIsConnected()) {
        realtimeProjectService.disconnect();
      }
    };
  }, []);

  // Real-time creation handlers
  const startRealtimeCreation = async () => {
    if (!selectedTemplate) {
      toast.error('Please select a template first');
      return;
    }
    
    try {
      // Create real-time session
      const sessionResponse = await realtimeProjectService.createSession();
      setRealtimeSession(sessionResponse);
      
      // Connect to WebSocket
      await realtimeProjectService.connectWebSocket(
        // onProgress
        (progressData) => {
          setRealtimeProgress(progressData);
          
          // Update chat with progress
          if (progressData.overall_progress % 10 === 0) { // Update every 10%
            setChatMessages(prev => [...prev, {
              type: 'ai',
              content: `🔄 Progress: ${Math.round(progressData.overall_progress)}% complete...`
            }]);
          }
        },
        // onComplete
        (completionData) => {
          setIsRealtimeBuilding(false);
          setIsGenerating(false);
          setCurrentProject(completionData.project);
          
          toast.success(completionData.message);
          setChatMessages(prev => [...prev, {
            type: 'ai',
            content: `🎉 ${completionData.message}`
          }]);
        },
        // onError
        (errorMessage) => {
          setIsRealtimeBuilding(false);
          setIsGenerating(false);
          toast.error(errorMessage);
          
          setChatMessages(prev => [...prev, {
            type: 'ai',
            content: `❌ Error: ${errorMessage}`
          }]);
        }
      );
      
      setWebsocketConnected(true);
      setIsRealtimeBuilding(true);
      setIsGenerating(true);
      
      // Start project creation
      const projectName = `${selectedTemplate.name.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}`;
      
      const projectData = {
        name: projectName,
        analysis: {
          project_type: selectedTemplate.id,
          features: selectedTemplate.features,
          description: selectedTemplate.description
        },
        tech_stack: selectedFrameworks
      };
      
      await realtimeProjectService.startProjectCreation(projectData);
      
    } catch (error) {
      console.error('Real-time creation error:', error);
      toast.error('Failed to start real-time creation');
      setIsGenerating(false);
      setIsRealtimeBuilding(false);
    }
  };

  const cancelRealtimeCreation = async () => {
    try {
      await realtimeProjectService.cancelCreation();
      setIsRealtimeBuilding(false);
      setIsGenerating(false);
      setRealtimeProgress(null);
      
      toast.success('Project creation cancelled');
      setChatMessages(prev => [...prev, {
        type: 'ai',
        content: '🛑 Project creation was cancelled'
      }]);
    } catch (error) {
      console.error('Cancellation error:', error);
      toast.error('Failed to cancel creation');
    }
  };

  // Framework selection handlers
  const handleFrameworkSelect = (category, framework) => {
    setSelectedFrameworks(prev => ({
      ...prev,
      [category]: framework
    }));
  };

  const getFrameworkRecommendations = async (templateId) => {
    if (!selectedTemplate) return;
    
    try {
      const analysis = {
        project_type: templateId,
        features: selectedTemplate.features
      };
      
      const response = await frameworkService.getFrameworkRecommendations(analysis);
      setFrameworkRecommendations(response.recommendations);
    } catch (error) {
      console.error('Failed to get recommendations:', error);
    }
  };

  const handleBuildWithFrameworks = async () => {
    if (!selectedTemplate) {
      toast.error('Please select a template first');
      return;
    }
    
    const projectName = `${selectedTemplate.name.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}`;
    
    try {
      setIsGenerating(true);
      
      const analysis = {
        project_type: selectedTemplate.id,
        features: selectedTemplate.features,
        description: selectedTemplate.description
      };
      
      const projectData = {
        name: projectName,
        analysis,
        frontend_framework: selectedFrameworks.frontend,
        backend_framework: selectedFrameworks.backend,
        database: selectedFrameworks.database
      };
      
      const response = await frameworkService.generateProjectWithCustomStack(projectData);
      
      if (response.success) {
        toast.success(response.message);
        setChatMessages(prev => [...prev, {
          type: 'ai',
          content: `🎉 Successfully generated ${response.project.name} using ${selectedFrameworks.frontend} + ${selectedFrameworks.backend} + ${selectedFrameworks.database}!`
        }]);
        
        setCurrentProject(response.project);
        startBuildProcess(`Generated ${selectedTemplate.name}`);
      }
      
    } catch (error) {
      toast.error('Failed to generate project');
      console.error('Generation error:', error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <Container>
      <Header>
        <Title>
          <Bot size={40} style={{ verticalAlign: 'middle', marginRight: '10px' }} />
          AI Application Builder
          <Sparkles size={30} style={{ marginLeft: '10px', verticalAlign: 'middle' }} />
        </Title>
        <Subtitle>
          Transform your ideas into production-ready applications using natural language. 
          Build unlimited React + FastAPI + MySQL applications with AI assistance.
        </Subtitle>
      </Header>

      <MainContent>
        <div>
          <BuilderSection>
            <SectionTitle>
              <MessageSquare size={24} />
              Chat with AI Builder
            </SectionTitle>
            
            <ChatInterface>
              <ChatMessages>
                {chatMessages.map((message, index) => (
                  <Message key={index} className={message.type}>
                    <div className="content">{message.content}</div>
                  </Message>
                ))}
                {isGenerating && (
                  <Message className="ai">
                    <div className="content">
                      <LoadingSpinner>
                        <Loader size={16} />
                      </LoadingSpinner>
                      <span style={{ marginLeft: '8px' }}>AI is thinking...</span>
                    </div>
                  </Message>
                )}
              </ChatMessages>
              
              <ChatInput>
                <Input
                  type="text"
                  placeholder="Describe the application you want to build..."
                  value={inputMessage}
                  onChange={(e) => setInputMessage(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                />
                <SendButton onClick={handleSendMessage} disabled={isGenerating}>
                  <Send size={16} />
                  Send
                </SendButton>
              </ChatInput>
            </ChatInterface>

            <div style={{ marginTop: '1rem' }}>
              <h4 style={{ marginBottom: '0.5rem', color: '#64748b', fontSize: '0.875rem' }}>
                💡 Try these examples:
              </h4>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
                {examplePrompts.map((prompt, index) => (
                  <button
                    key={index}
                    onClick={() => setInputMessage(prompt)}
                    style={{
                      background: '#f1f5f9',
                      border: '1px solid #e2e8f0',
                      borderRadius: '1rem',
                      padding: '0.5rem 1rem',
                      fontSize: '0.875rem',
                      color: '#64748b',
                      cursor: 'pointer',
                      transition: 'all 0.2s ease'
                    }}
                    onMouseOver={(e) => {
                      e.target.style.background = '#667eea';
                      e.target.style.color = 'white';
                    }}
                    onMouseOut={(e) => {
                      e.target.style.background = '#f1f5f9';
                      e.target.style.color = '#64748b';
                    }}
                  >
                    {prompt}
                  </button>
                ))}
              </div>
            </div>
          </BuilderSection>

          <BuilderSection style={{ marginTop: '2rem' }}>
            <SectionTitle>
              <Layout size={24} />
              Quick Start Templates
            </SectionTitle>
            
            <TemplateGrid>
              {templates.map((template) => (
                <TemplateCard
                  key={template.id}
                  selected={selectedTemplate?.id === template.id}
                  onClick={() => handleTemplateSelect(template)}
                >
                  <TemplateIcon>
                    <template.icon size={24} />
                  </TemplateIcon>
                  <TemplateName>{template.name}</TemplateName>
                  <TemplateDescription>{template.description}</TemplateDescription>
                  <div style={{ marginTop: '1rem' }}>
                    {template.features.map((feature, index) => (
                      <span
                        key={index}
                        style={{
                          display: 'inline-block',
                          background: '#f1f5f9',
                          color: '#64748b',
                          padding: '0.25rem 0.5rem',
                          borderRadius: '0.5rem',
                          fontSize: '0.75rem',
                          margin: '0.125rem',
                        }}
                      >
                        {feature}
                      </span>
                    ))}
                  </div>
                </TemplateCard>
              ))}
            </TemplateGrid>

            {selectedTemplate && (
              <>
                <FrameworkSection>
                  <SectionTitle>
                    <Cpu size={20} />
                    Technology Stack
                    {frameworkRecommendations && (
                      <RecommendationBadge>
                        <Star size={12} />
                        AI Recommended
                      </RecommendationBadge>
                    )}
                  </SectionTitle>
                  
                  <AdvancedToggle 
                    onClick={() => {
                      setShowAdvancedOptions(!showAdvancedOptions);
                      if (!showAdvancedOptions) {
                        getFrameworkRecommendations(selectedTemplate.id);
                      }
                    }}
                  >
                    <Settings size={16} />
                    {showAdvancedOptions ? 'Use Default Stack' : 'Advanced Framework Selection'}
                    <ChevronDown 
                      size={16} 
                      style={{ 
                        transform: showAdvancedOptions ? 'rotate(180deg)' : 'rotate(0deg)',
                        transition: 'transform 0.3s ease'
                      }} 
                    />
                  </AdvancedToggle>
                  
                  {showAdvancedOptions && supportedFrameworks && (
                    <>
                      {['frontend', 'backend', 'database'].map(category => (
                        <div key={category} style={{ marginBottom: '1.5rem' }}>
                          <h4 style={{ 
                            fontSize: '1rem', 
                            fontWeight: '600', 
                            color: '#1e293b', 
                            marginBottom: '0.75rem',
                            textTransform: 'capitalize'
                          }}>
                            {category} Framework
                          </h4>
                          
                          <FrameworkGrid>
                            {supportedFrameworks[category] && Object.entries(supportedFrameworks[category]).map(([key, framework]) => (
                              <FrameworkCard
                                key={key}
                                selected={selectedFrameworks[category] === key}
                                onClick={() => handleFrameworkSelect(category, key)}
                              >
                                <FrameworkHeader>
                                  <FrameworkIcon>{framework.icon || '🔧'}</FrameworkIcon>
                                  <FrameworkName>{framework.name}</FrameworkName>
                                  {frameworkRecommendations?.primary?.[category] === key && (
                                    <RecommendationBadge>
                                      <Star size={10} />
                                      Recommended
                                    </RecommendationBadge>
                                  )}
                                </FrameworkHeader>
                                <FrameworkDescription>{framework.description}</FrameworkDescription>
                              </FrameworkCard>
                            ))}
                          </FrameworkGrid>
                        </div>
                      ))}
                      
                      <TechStackPreview>
                        <h4 style={{ fontSize: '1rem', fontWeight: '600', color: '#1e293b', marginBottom: '0.75rem' }}>
                          Selected Technology Stack
                        </h4>
                        {Object.entries(selectedFrameworks).map(([category, framework]) => (
                          <TechStackItem key={category}>
                            <TechStackLabel>{category}:</TechStackLabel>
                            <TechStackValue>
                              {supportedFrameworks[category]?.[framework]?.icon || '🔧'}
                              {supportedFrameworks[category]?.[framework]?.name || framework}
                            </TechStackValue>
                          </TechStackItem>
                        ))}
                      </TechStackPreview>
                    </>
                  )}
                </FrameworkSection>
                
                <ActionButton 
                  onClick={showAdvancedOptions ? startRealtimeCreation : startRealtimeCreation}
                  disabled={isGenerating}
                >
                  {isGenerating ? (
                    <>
                      <LoadingSpinner><Loader size={20} /></LoadingSpinner>
                      {isRealtimeBuilding ? 'Building...' : 'Generating...'}
                    </>
                  ) : (
                    <>
                      <Rocket size={20} />
                      Build {selectedTemplate.name}
                      {showAdvancedOptions && (
                        <span style={{ fontSize: '0.875rem', opacity: 0.8 }}>
                          ({selectedFrameworks.frontend} + {selectedFrameworks.backend} + {selectedFrameworks.database})
                        </span>
                      )}
                    </>
                  )}
                </ActionButton>
                
                {isRealtimeBuilding && (
                  <ActionButton 
                    onClick={cancelRealtimeCreation}
                    style={{ 
                      background: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)',
                      marginTop: '0.5rem'
                    }}
                  >
                    <AlertCircle size={20} />
                    Cancel Creation
                  </ActionButton>
                )}
              </>
            )}
          </BuilderSection>
        </div>

        <Sidebar>
          <ProgressCard>
            <SectionTitle style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>
              <Cog size={20} />
              Build Progress
            </SectionTitle>
            
            {buildSteps.map((step) => (
              <ProgressStep key={step.id} className={step.status}>
                <StepIcon className={step.status}>
                  {step.status === 'completed' ? (
                    <CheckCircle size={16} />
                  ) : step.status === 'active' ? (
                    <LoadingSpinner>
                      <Loader size={16} />
                    </LoadingSpinner>
                  ) : (
                    step.id
                  )}
                </StepIcon>
                <span>{step.name}</span>
              </ProgressStep>
            ))}

            {currentProject && buildSteps.every(step => step.status === 'completed') && (
              <ActionButton onClick={handleDeployApp} style={{ marginTop: '1rem' }}>
                <Rocket size={20} />
                Deploy Application
              </ActionButton>
            )}
          </ProgressCard>

          {realtimeProgress && (
            <ProgressCard style={{ marginTop: '1rem' }}>
              <SectionTitle style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>
                <Wifi size={20} />
                Real-time Progress
                {websocketConnected && (
                  <span style={{ 
                    fontSize: '0.75rem', 
                    background: '#10b981', 
                    color: 'white', 
                    padding: '0.25rem 0.5rem', 
                    borderRadius: '0.5rem', 
                    marginLeft: '0.5rem' 
                  }}>
                    Connected
                  </span>
                )}
              </SectionTitle>
              
              <div style={{ marginBottom: '1rem' }}>
                <div style={{ 
                  display: 'flex', 
                  justifyContent: 'space-between', 
                  marginBottom: '0.5rem', 
                  fontSize: '0.875rem' 
                }}>
                  <span>Overall Progress</span>
                  <span>{Math.round(realtimeProgress.overall_progress)}%</span>
                </div>
                <div style={{ 
                  height: '8px', 
                  background: '#e2e8f0', 
                  borderRadius: '4px', 
                  overflow: 'hidden' 
                }}>
                  <div style={{ 
                    height: '100%', 
                    width: `${realtimeProgress.overall_progress}%`, 
                    background: 'linear-gradient(90deg, #667eea, #764ba2)', 
                    transition: 'width 0.3s ease' 
                  }} />
                </div>
              </div>
              
              <div>
                {realtimeProgress.steps && realtimeProgress.steps.map((step, index) => (
                  <div 
                    key={index} 
                    style={{ 
                      display: 'flex', 
                      alignItems: 'center', 
                      padding: '0.5rem 0', 
                      borderBottom: '1px solid #f1f5f9' 
                    }}
                  >
                    <div style={{ marginRight: '0.75rem' }}>
                      {step.status === 'completed' ? (
                        <CheckCircle size={16} color="#10b981" />
                      ) : step.status === 'active' ? (
                        <LoadingSpinner>
                          <Loader size={16} color="#667eea" />
                        </LoadingSpinner>
                      ) : (
                        <div style={{ 
                          width: '16px', 
                          height: '16px', 
                          borderRadius: '50%', 
                          background: '#cbd5e1' 
                        }} />
                      )}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ 
                        fontSize: '0.875rem', 
                        fontWeight: step.status === 'active' ? '600' : 'normal',
                        color: step.status === 'active' ? '#667eea' : '#1e293b'
                      }}>
                        {step.name}
                      </div>
                      {step.details && (
                        <div style={{ 
                          fontSize: '0.75rem', 
                          color: '#64748b', 
                          marginTop: '0.125rem' 
                        }}>
                          {step.details.current_file || step.details.current_task || step.details.current_optimization}
                        </div>
                      )}
                    </div>
                    <div style={{ fontSize: '0.75rem', color: '#64748b' }}>
                      {step.status === 'completed' ? '100%' : 
                       step.status === 'active' ? `${Math.round(step.progress)}%` : '0%'}
                    </div>
                  </div>
                ))}
              </div>
            </ProgressCard>
          )}

          <ProgressCard>
            <SectionTitle style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>
              <Zap size={20} />
              Recent Projects
            </SectionTitle>
            
            <div style={{ color: '#64748b', textAlign: 'center', padding: '2rem 0' }}>
              {currentProject ? (
                <div>
                  <h4 style={{ color: '#1e293b', marginBottom: '0.5rem' }}>
                    {currentProject.name}
                  </h4>
                  <p style={{ fontSize: '0.875rem' }}>
                    Started {currentProject.startTime.toLocaleTimeString()}
                  </p>
                </div>
              ) : (
                <p>No projects yet. Start building your first application!</p>
              )}
            </div>
          </ProgressCard>
        </Sidebar>
      </MainContent>
    </Container>
  );
}

export default Builder;
